package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

public class GsonBuilderTest {

  @Test
  void testSetLenient() throws Exception {
    GsonBuilder builder = new GsonBuilder();
    // Initially lenient should be default (false)
    Field lenientField = GsonBuilder.class.getDeclaredField("lenient");
    lenientField.setAccessible(true);
    boolean initialLenient = (boolean) lenientField.get(builder);
    assertFalse(initialLenient);

    // Call setLenient and verify it returns the same instance
    GsonBuilder returned = builder.setLenient();
    assertSame(builder, returned);

    // Verify lenient field is now true
    boolean lenientAfter = (boolean) lenientField.get(builder);
    assertTrue(lenientAfter);
  }
}
